var tx = 0, ty = 0, tr = 0, cx = 0, cy = 0, cr = 0;
ba.addEventListener("pointermove", function(e){
  var r = ba.getBoundingClientRect();
  tx = e.clientX - r.left; ty = e.clientY - r.top;
  tr = Math.min(r.width, r.height) * 0.32;
});
ba.addEventListener("pointerleave", function(){ tr = 0; });
function frame(){
  cx += (tx - cx) * 0.18; cy += (ty - cy) * 0.18; cr += (tr - cr) * 0.16;
  lens.style.clipPath = "circle(" + cr + "px at " + cx + "px " + cy + "px)";
  requestAnimationFrame(frame);
}
requestAnimationFrame(frame);

