.scroll-track { min-height: 240vh; position: relative; }
.sticky-stage { position: sticky; top: 0; height: 100vh;
  display: flex; align-items: center; justify-content: center; }
.ba { --pos: 100%; position: relative; aspect-ratio: 16 / 10;
  overflow: hidden; }
.ba-before { clip-path: inset(0 calc(100% - var(--pos)) 0 0); }
.ba-handle { position: absolute; top: 0; bottom: 0;
  left: var(--pos); width: 2px; background: #fff; }

var track = document.querySelector(".scroll-track");
var ba = document.querySelector(".ba");
function calc(){
  var rect = track.getBoundingClientRect();
  var max = Math.max(1, rect.height - window.innerHeight);
  return Math.max(0, Math.min(1, -rect.top / max));
}
function tick(){
  var p = calc();
  var t = Math.max(0, Math.min(1, (p - 0.06) / 0.88));
  ba.style.setProperty("--pos", ((1 - t) * 100) + "%");
}
window.addEventListener("scroll", tick, { passive: true });
tick();

