var KEYS = [0.5, 0.92, 0.08, 0.5];   // 왕복 스윕 키프레임
var DUR = [700, 1200, 700];          // 구간별 ms
function startSweep(){
  sweeping = true;
  var t0 = performance.now();
  function step(now){
    if (!sweeping) return;            // 드래그 시작 시 즉시 양보
    var t = now - t0, acc = 0, i = 0;
    while (i < DUR.length && t > acc + DUR[i]) { acc += DUR[i]; i++; }
    if (i >= DUR.length) { setPos(0.5); sweeping = false; return; }
    var local = (t - acc) / DUR[i];
    setPos(KEYS[i] + (KEYS[i + 1] - KEYS[i]) * easeInOutCubic(local));
    requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}
ba.addEventListener("pointerdown", function(){ sweeping = false; });
startSweep();
